import{_ as a,o as t,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Referencia de Scalers","description":"","frontmatter":{},"headers":[],"relativePath":"es/scalers/reference.md","filePath":"es/scalers/reference.md"}'),n={name:"es/scalers/reference.md"};function r(i,e,d,s,c,p){return t(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="referencia-de-scalers" tabindex="-1"><i class="ph ph-sliders"></i> Referencia de Scalers <a class="header-anchor" href="#referencia-de-scalers" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; Referencia de Scalers&quot;">​</a></h1><p>Web Adaptive Performance incluye un conjunto de Scalers especializados (módulos de optimización). El Indexer selecciona automáticamente qué Scaler implementar en función de su impacto visual (<code>Visual Impact</code>) y del tipo de cuello de botella actual (<code>Target</code>: CPU o GPU).</p><h2 id="matriz-de-compatibilidad" tabindex="-1">Matriz de Compatibilidad <a class="header-anchor" href="#matriz-de-compatibilidad" aria-label="Permalink to &quot;Matriz de Compatibilidad&quot;">​</a></h2><p>A continuación se muestra la matriz de compatibilidad y una descripción de todos los módulos disponibles.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Scaler</th><th style="text-align:left;">Pipeline</th><th style="text-align:left;">Target</th><th style="text-align:left;">Descripción</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Reduce la resolución de renderizado, disminuyendo radicalmente la carga en el Fillrate de la GPU. <em>Ve los detalles a continuación.</em></td></tr><tr><td style="text-align:left;"><strong>Shadows Quality</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Desactiva las sombras por fases.<br>En <strong>URP</strong>, primero desactiva las sombras suaves, luego las sombras de luces adicionales y, finalmente, las sombras principales.<br>En <strong>BiRP</strong>, cambia las sombras al modo <code>Hard Only</code> antes de desactivarlas por completo.</td></tr><tr><td style="text-align:left;"><strong>Shadow Cascades</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU/GPU</td><td style="text-align:left;">Reduce el número de cascadas de sombras. Disminuye las Draw Calls de la CPU y la carga en la GPU.</td></tr><tr><td style="text-align:left;"><strong>Shadow Distance</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Acorta la distancia de dibujado de las sombras.</td></tr><tr><td style="text-align:left;"><strong>Shadow Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Reduce la resolución de los mapas de sombras (Shadow Maps).</td></tr><tr><td style="text-align:left;"><strong>Anti Aliasing</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Disminuye la calidad del anti-aliasing (MSAA) hasta su completa desactivación.</td></tr><tr><td style="text-align:left;"><strong>LOD Bias</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Obliga a Unity a cambiar a modelos LOD de bajos polígonos a una distancia más corta de la cámara.</td></tr><tr><td style="text-align:left;"><strong>Camera Clip</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Reduce el parámetro <code>Far Clip Plane</code> en las cámaras de destino, eliminando los objetos distantes del renderizado.</td></tr><tr><td style="text-align:left;"><strong>Layer Culling</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">Reduce proporcionalmente la distancia de descarte (Culling Distance) para capas de objetos específicos.</td></tr><tr><td style="text-align:left;"><strong>Physics Step</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">Disminuye la frecuencia de los cálculos físicos. Salva el rendimiento durante cargas físicas pesadas en el navegador.</td></tr><tr><td style="text-align:left;"><strong>LUT</strong></td><td style="text-align:left;"><code>Solo URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Reduce el tamaño de las tablas LUT de Color Grading al mínimo.</td></tr><tr><td style="text-align:left;"><strong>Mesh LOD Threshold</strong></td><td style="text-align:left;"><code>Unity 6+</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Altera el parámetro <code>meshLodThreshold</code>, introducido en Unity 6.2, para cambios agresivos de LOD.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Cuidado con el Physics Step Scaler</p><p>El Scaler de física altera directamente el parámetro <code>Time.fixedDeltaTime</code>. Si un controlador de personaje o la mecánica del juego dependen estrictamente de fotogramas físicos fijos sin interpolación (Interpolation), el movimiento de los objetos puede volverse tartamudo (&quot;gaguejante&quot;) en niveles de baja calidad.</p></div><div class="tip custom-block"><p class="custom-block-title">Restablecimiento de la Configuración de los Scalers</p><p>Si has experimentado con los parámetros del Scaler (por ejemplo, modificando el <code>Min Bound</code> o <code>Max Level</code>) y deseas volver a los valores predeterminados, simplemente apaga y enciende el interruptor en la ventana de <em>Project Settings</em>. El plugin recreará automáticamente el módulo con la configuración base.</p></div><h2 id="analisis-resolution-scaler" tabindex="-1">Análisis: Resolution Scaler <a class="header-anchor" href="#analisis-resolution-scaler" aria-label="Permalink to &quot;Análisis: Resolution Scaler&quot;">​</a></h2><p>Esta es la herramienta más potente del plugin, que garantiza el mayor aumento de FPS. Su funcionamiento varía drásticamente según el pipeline activo.</p><h3 id="en-modo-urp-universal-render-pipeline" tabindex="-1">En Modo URP (Universal Render Pipeline) <a class="header-anchor" href="#en-modo-urp-universal-render-pipeline" aria-label="Permalink to &quot;En Modo URP (Universal Render Pipeline)&quot;">​</a></h3><p>En URP, el escalado funciona a la perfección. El plugin interfiere directamente con la propiedad <code>renderScale</code> en el <code>UniversalRenderPipelineAsset</code>. La interfaz (UI) permanece nítida automáticamente, ya que URP es capaz de renderizar el Canvas sobre un mundo 3D escalado.</p><h3 id="en-modo-birp-built-in-render-pipeline" tabindex="-1">En Modo BiRP (Built-in Render Pipeline) <a class="header-anchor" href="#en-modo-birp-built-in-render-pipeline" aria-label="Permalink to &quot;En Modo BiRP (Built-in Render Pipeline)&quot;">​</a></h3><p>Históricamente, BiRP carece de una configuración de Render Scale integrada que funcione en WebGL sin romper la interfaz o causar fallos (FBO Feedback Loop). WebAP resuelve esto ofreciendo dos estrategias exclusivas.</p><h4 id="modo-1-nativebrowserscaling-escala-nativa-del-navegador" tabindex="-1">Modo 1: NativeBrowserScaling (Escala Nativa del Navegador) <a class="header-anchor" href="#modo-1-nativebrowserscaling-escala-nativa-del-navegador" aria-label="Permalink to &quot;Modo 1: NativeBrowserScaling (Escala Nativa del Navegador)&quot;">​</a></h4><p>El plugin escala el elemento HTML <code>&lt;canvas&gt;</code> directamente a través de Native Loop Spoofing (inyectando en los parámetros <code>devicePixelRatio</code> del navegador).</p><ul><li><strong>Pros:</strong> Máximo rendimiento, cero sobrecarga del lado de la GPU.</li><li><strong>Contras:</strong> La interfaz del juego se vuelve borrosa junto con los gráficos 3D. Este modo solo funciona en una build compilada de WebGL (ningún cambio será visible en el Unity Editor).</li></ul><h4 id="modo-2-rendertexturescaling" tabindex="-1">Modo 2: RenderTextureScaling <a class="header-anchor" href="#modo-2-rendertexturescaling" aria-label="Permalink to &quot;Modo 2: RenderTextureScaling&quot;">​</a></h4><p>El plugin redirige la renderización de las cámaras de destino a una textura compartida comprimida y utiliza una Compositor Camera oculta para presentar la imagen.</p><ul><li><strong>Pros:</strong> El mundo 3D se escala, mientras que la interfaz de usuario (texto, botones) permanece nítida.</li><li><strong>Contras:</strong> Agrega una carga marginal a la GPU debido a la operación Blit (copiando la textura a la pantalla).</li></ul><div class="info custom-block"><p class="custom-block-title">Corrección de Clics del Ratón (Raycasts)</p><p>Cuando se usa RenderTextureScaling, las coordenadas de la pantalla virtual se comprimen. Para garantizar que los clics del ratón en objetos 3D continúen funcionando correctamente, el plugin reemplaza automáticamente los componentes estándar <code>PhysicsRaycaster</code> y <code>Physics2DRaycaster</code> en las cámaras de destino con componentes personalizados <code>WebScaledPhysicsRaycaster</code>. La precisión de los rayos sigue siendo infalible a cualquier escala.</p></div><h2 id="¿como-preservar-la-claridad-de-la-ui-para-birp-rendertexturescaling" tabindex="-1">¿Cómo Preservar la Claridad de la UI? (Para BiRP RenderTextureScaling) <a class="header-anchor" href="#¿como-preservar-la-claridad-de-la-ui-para-birp-rendertexturescaling" aria-label="Permalink to &quot;¿Cómo Preservar la Claridad de la UI? (Para BiRP RenderTextureScaling)&quot;">​</a></h2><p>Para mantener la interfaz nítida mientras se escalan los gráficos 3D en BiRP con RenderTextureScaling, debes configurar tu Canvas correctamente. Selecciona una de estas dos opciones:</p><h3 id="opcion-1-screen-space-overlay-recomendada" tabindex="-1">Opción 1: Screen Space - Overlay (Recomendada) <a class="header-anchor" href="#opcion-1-screen-space-overlay-recomendada" aria-label="Permalink to &quot;Opción 1: Screen Space - Overlay (Recomendada)&quot;">​</a></h3><p>El método más simple y confiable. El plugin maneja todo el trabajo automáticamente.</p><ol><li>Selecciona tu <strong>Canvas</strong> en la jerarquía de la escena.</li><li>En el componente Canvas, establece el <strong>Render Mode</strong> en <code>Screen Space - Overlay</code>.<br><em>Resultado:</em> Unity renderiza la interfaz encima del mundo 3D comprimido a una resolución del 100% nativa.</li></ol><h3 id="opcion-2-screen-space-camera-para-capas-complejas" tabindex="-1">Opción 2: Screen Space - Camera (Para Capas Complejas) <a class="header-anchor" href="#opcion-2-screen-space-camera-para-capas-complejas" aria-label="Permalink to &quot;Opción 2: Screen Space - Camera (Para Capas Complejas)&quot;">​</a></h3><p>Se usa si necesitas mezclar modelos 3D, partículas y UI. Tendrás que separar el renderizado en dos cámaras.</p><ol><li><strong>Cámara Principal (3D):</strong> Asegúrate de que su etiqueta (tag) esté especificada en la matriz <code>Target Tags</code> del Scaler. En el campo <code>Culling Mask</code>, desmarca la capa <strong>UI</strong>. Establece el <code>Depth</code> en <code>0</code>.</li><li><strong>Cámara de UI (Nueva):</strong> Crea una nueva cámara para renderizar la interfaz. <strong>No</strong> agregues su etiqueta a la configuración del Scaler. <ul><li>Establece <code>Clear Flags</code> en <code>Depth Only</code> (para que la cámara no borre el fondo 3D).</li><li>Establece el <code>Culling Mask</code> exclusivamente en la capa <strong>UI</strong>.</li><li>Establece el <code>Depth</code> en <code>1</code> (mayor que el de la cámara principal).</li></ul></li><li><strong>Configuración del Canvas:</strong> Establece el <strong>Render Mode</strong> en <code>Screen Space - Camera</code> y arrastra tu nueva Cámara de UI a la ranura <code>Render Camera</code>.</li></ol>',28)])])}const g=a(n,[["render",r]]);export{u as __pageData,g as default};
